sql:
SELECT UPPER(casino_name) AS Casino_Name
FROM casinos
WHERE payout_rate = 98.5 AND trustworthiness > 9.0;

SELECT AVG(trustworthiness) AS average_trustworthiness
FROM casinos
WHERE payout_rate > 90;

external_knowledge:
- 'trusted casinos' refers to casinos with the highest average trustworthiness scores;
- 'top 3' means the three casinos with the highest trustworthiness;
- 'total bonus amount' is the sum of all bonus amounts offered by a casino.

- 'Trusted' category indicates casinos that are known for their reliability and security;
- Trustworthiness score is a measure of a casino's reputation and reliability;
- Payout rate is the average percentage of money wagered that is returned to players as winnings.

- "Most trustworthy" refers to the top 5 casinos ranked by trustworthiness score;
- "Most generous" refers to the top 5 casinos ranked by payout rate;
- The final list is ordered by the highest average payout rate.

sql:
